```class Solution {
    public boolean equalFrequency(String word) {
        int[] freq = new int[26];
        for (char c : word.toCharArray()) {
            freq[c - 'a']++;
        }
        for (int i = 0; i < word.length(); i++) {
            freq[word.charAt(i) - 'a']--;
            boolean flag = true;
            for (int j = 0; j < 26; j++) {
                if (freq[j] != 0) {
                    flag = false;
                    break;
                }
            }
            if (flag) {
                return true;
            }
            freq[word.charAt(i) - 'a']++;
        }
        return false;
    }
}```
